import React, { useState } from "react";

function App() {

const [hcpName, setHcpName] = useState("");
const [interactionType, setInteractionType] = useState("Meeting");
const [date, setDate] = useState("");
const [topics, setTopics] = useState("");
const [sentiment, setSentiment] = useState("Neutral");
const [followUp, setFollowUp] = useState("");

const [aiText, setAiText] = useState("");

const askAI = async () => {

if (!aiText) {
alert("Please enter interaction text");
return;
}

try {

```
const response = await fetch("http://127.0.0.1:8000/ai-log", {
  method: "POST",
  headers: {
    "Content-Type": "application/json"
  },
  body: JSON.stringify({ text: aiText })
});

const data = await response.json();

setHcpName(data.hcpName || "");
setInteractionType(data.interactionType || "Meeting");
setTopics(data.topics || "");
setSentiment(data.sentiment || "Neutral");
setFollowUp(data.followUp || "");
```

} catch (error) {
console.error(error);
alert("AI request failed");
}

};

const logInteraction = () => {

const data = {
hcpName,
interactionType,
date,
topics,
sentiment,
followUp
};

console.log("Logged Interaction:", data);

alert("Interaction logged successfully");

};

return (

<div style={page}>

<div style={formCard}>

<h2 style={{marginBottom:"20px"}}>Log HCP Interaction</h2>

<input
placeholder="HCP Name"
style={input}
value={hcpName}
onChange={(e)=>setHcpName(e.target.value)}
/>

<select
style={input}
value={interactionType}
onChange={(e)=>setInteractionType(e.target.value)}

>

<option>Meeting</option>
<option>Call</option>
<option>Email</option>

</select>

<input
type="date"
style={input}
value={date}
onChange={(e)=>setDate(e.target.value)}
/>

<textarea
placeholder="Topics Discussed"
style={input}
value={topics}
onChange={(e)=>setTopics(e.target.value)}
/>

<select
style={input}
value={sentiment}
onChange={(e)=>setSentiment(e.target.value)}
>

<option>Positive</option>
<option>Neutral</option>
<option>Negative</option>

</select>

<textarea
placeholder="Follow-up Actions"
style={input}
value={followUp}
onChange={(e)=>setFollowUp(e.target.value)}
/>

<button
style={button}
onClick={logInteraction}
>
Log Interaction
</button>

</div>


<div style={aiCard}>

<h3>AI Assistant</h3>

<p style={{color:"#666"}}>
Describe the interaction and AI will auto-fill the form
</p>

<textarea
placeholder="Example: Met Dr Sharma and discussed Product X..."
style={chat}
value={aiText}
onChange={(e)=>setAiText(e.target.value)}
/>

<button
style={aiButton}
onClick={askAI}
>
Ask AI
</button>

</div>

</div>

);

}


/* PAGE */

const page = {

height:"100vh",
display:"flex",
justifyContent:"center",
alignItems:"center",
gap:"40px",
background:"#e6f4ea",
fontFamily:"Inter, sans-serif"

};


/* FORM */

const formCard = {

width:"420px",
padding:"30px",
borderRadius:"16px",
background:"white",
boxShadow:"0 10px 30px rgba(0,0,0,0.1)"

};


/* AI CARD */

const aiCard = {

width:"350px",
padding:"25px",
borderRadius:"16px",
background:"white",
boxShadow:"0 10px 30px rgba(0,0,0,0.1)"

};


/* INPUT */

const input = {

width:"100%",
padding:"12px",
marginBottom:"15px",
borderRadius:"8px",
border:"1px solid #ddd"

};


/* BUTTON */

const button = {

width:"100%",
padding:"12px",
border:"none",
borderRadius:"8px",
background:"#3b82f6",
color:"white",
fontSize:"15px",
cursor:"pointer"

};


const aiButton = {

width:"100%",
padding:"12px",
marginTop:"10px",
border:"none",
borderRadius:"8px",
background:"#10b981",
color:"white",
cursor:"pointer"

};


/* CHAT */

const chat = {

width:"100%",
height:"120px",
padding:"10px",
borderRadius:"8px",
border:"1px solid #ddd",
marginTop:"10px"

};


export default App;
